use std::env;
use std::fs;
use std::io;
use std::path::{Path, PathBuf};

fn visit_dir(dir: &Path, root: &Path, out: &mut Vec<String>) -> io::Result<()> {
  for entry in fs::read_dir(dir)? {
    let entry = entry?;
    let path = entry.path();
    let ty = entry.file_type()?;
    if ty.is_dir() {
      visit_dir(&path, root, out)?;
      continue;
    }
    if !ty.is_file() {
      continue;
    }

    let Some(ext) = path.extension().and_then(|ext| ext.to_str()) else {
      continue;
    };
    let ext = ext.to_ascii_lowercase();
    if ext != "yaml" && ext != "yml" && ext != "toml" {
      continue;
    }

    let rel = path
      .strip_prefix(root)
      .expect("file path is under knowledge-base root")
      .to_string_lossy()
      .replace('\\', "/");
    out.push(rel);
  }
  Ok(())
}

fn main() -> io::Result<()> {
  let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR"));
  let out_dir = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR"));

  let mut files = Vec::new();
  for top in ["core", "node", "web", "ecosystem"] {
    println!("cargo:rerun-if-changed={top}");
    let dir = manifest_dir.join(top);
    if dir.exists() {
      visit_dir(&dir, &manifest_dir, &mut files)?;
    }
  }

  files.sort();

  for file in &files {
    println!("cargo:rerun-if-changed={file}");
  }

  let mut generated = String::new();
  generated.push_str("// @generated by knowledge-base/build.rs\n");
  generated.push_str("pub(crate) static BUNDLED_KB_FILES: &[BundledKbFile] = &[\n");
  for file in &files {
    let ext = Path::new(file)
      .extension()
      .and_then(|ext| ext.to_str())
      .unwrap_or("")
      .to_ascii_lowercase();
    let format = match ext.as_str() {
      "yaml" | "yml" => "Yaml",
      "toml" => "Toml",
      other => panic!("unexpected knowledge base file extension: {other}"),
    };
    generated.push_str(&format!(
      "  BundledKbFile {{ path: {path:?}, format: BundledKbFormat::{format}, contents: include_str!(concat!(env!(\"CARGO_MANIFEST_DIR\"), \"/\", {path:?})) }},\n",
      path = file
    ));
  }
  generated.push_str("];\n");

  fs::write(out_dir.join("bundled_kb.rs"), generated)?;
  Ok(())
}

